import pybullet as p
import time
import pybullet_data
import cv2 
import numpy as np

p.connect(p.GUI)
p.setAdditionalSearchPath(pybullet_data.getDataPath())
p.loadURDF("plane.urdf")
# sphereUid = p.loadURDF("sphere_transparent.urdf", [0, 0, 2])
sphereUid = p.loadURDF("cube.urdf", [0, 0, 2])
cubeUid = p.loadURDF("cube.urdf", [1, 0, 2])



redSlider = p.addUserDebugParameter("red", 0, 1, 1)
greenSlider = p.addUserDebugParameter("green", 0, 1, 0)
blueSlider = p.addUserDebugParameter("blue", 0, 1, 0)
alphaSlider = p.addUserDebugParameter("alpha", 0, 1, 0.5)

red_cube2_slider = p.addUserDebugParameter("red_cube2", 0, 1, 0.5)
green_cube2_slider = p.addUserDebugParameter("green_cube2", 0, 1, 0.5)
blue_cube2_slider = p.addUserDebugParameter("blue_cube2", 0, 1, 0.5)
alpha_cube2_slider = p.addUserDebugParameter("alpha_cube2", 0, 1, 0.5)

running = True

while running:
  red = p.readUserDebugParameter(redSlider)
  green = p.readUserDebugParameter(greenSlider)
  blue = p.readUserDebugParameter(blueSlider)
  alpha = p.readUserDebugParameter(alphaSlider)
  
  red2 = p.readUserDebugParameter(red_cube2_slider)
  green2 = p.readUserDebugParameter(green_cube2_slider)
  blue2 = p.readUserDebugParameter(blue_cube2_slider)
  alpha2 = p.readUserDebugParameter(alpha_cube2_slider)
  
  p.changeVisualShape(sphereUid, -1, rgbaColor=[red, green, blue, alpha])
  p.changeVisualShape(cubeUid, -1, rgbaColor=[red2, green2, blue2, alpha2])
  
  for i in range(100):
    p.resetBasePositionAndOrientation(sphereUid, [0, 0, 2 + i * 0.01], [0, 0, 0, 1])
    time.sleep(0.01)
    if i == 77:
      width, height, rgbImg, depthImg, segImg = p.getCameraImage(640, 480,
                                                                  flags=p.ER_SEGMENTATION_MASK_OBJECT_AND_LINKINDEX,
                                                                  renderer=p.ER_BULLET_HARDWARE_OPENGL)
      rgb_array = np.array(rgbImg, dtype=np.uint8).reshape((height, width, 4))
      rgb_array = rgb_array[:, :, :3]
      bgr_array = cv2.cvtColor(rgb_array, cv2.COLOR_RGBA2BGR)
      # print(f"rgbImg.shape: {rgbImg.shape}")
      cv2.imwrite(f"output_{i}.png", bgr_array)

  # p.getCameraImage(640,
  #                  480,
  #                  flags=p.ER_SEGMENTATION_MASK_OBJECT_AND_LINKINDEX,
  #                  renderer=p.ER_BULLET_HARDWARE_OPENGL)
  
